const body = $input.item.json.body || $input.item.json;
return [{
  json: {
    environment:  body.environment || 'staging',
    version:      body.version || body.tag || 'unknown',
    deployed_by:  body.actor || body.deployed_by || 'CI',
    repo:         body.repository || 'stb-cms',
    commit:       body.commit_sha || body.sha || '',
    deploy_time:  new Date().toISOString(),
    run_markers:  body.test_markers || 'regression',
    workers:      body.parallel_workers || 2,
  }
}];

const data  = $input.item.json;
const s     = data.summary || {};
const deploy = $('Parse Deploy Event').item.json;

// Gate: pass if pass_pct >= 90 AND no errors
const PASS_THRESHOLD = 90;
const gate_passed = s.pass_pct >= PASS_THRESHOLD && s.errors === 0;

return [{
  json: {
    gate_passed,
    gate_threshold: PASS_THRESHOLD,
    summary: s,
    run_id: data.run_id,
    exit_code: data.exit_code,
    deploy,
    verdict: gate_passed ? 'APPROVED' : 'BLOCKED',
    reason: !gate_passed
      ? `Pass rate ${s.pass_pct}% below ${PASS_THRESHOLD}% threshold or ${s.errors} error(s) detected`
      : `All quality gates passed (${s.pass_pct}% pass rate)`,
  }
}];
